var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"민하 씨, 여고생인데 운전면허가 있었군요.","JPN":"ミウさん、女子高生なのに免許持ってるんですね。","ENG":"Minha, you're a high schooler, but you already have a driver's license.","TWN":"敏荷你是女高中生，卻有駕照呢。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"예전에 땄어. 혼자 돌아다닐 일이 많았거든.","JPN":"昔取ったんだ。一人で移動することが多かったし。","ENG":"I got it a while ago. I travel around on my own a lot.","TWN":"我以前考的。我常常一個人到處跑。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_PRIDE"}}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…민하 씨는 절 어떻게 찾았어요?","JPN":"……ミウさんは、どうやって私を見つけたんですか？","ENG":"...How did you find me?","TWN":"……你是怎麼找到我的？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_PRIDE"}}}},{"id":"L6_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"시니어가 의심 가는 장소 몇 군데를 짚어줬어. 그라운드 원에 사각지대가 그리 많진 않으니까.","JPN":"シニアが疑わしい場所をいくつかピックアップしてくれてね。そもそもグラウンド・ワンに死角はそんなに多くないから。","ENG":"The Senior pointed out a few suspicious locations. There aren't that many blind spots in Ground One.","TWN":"Senior點出了幾個可疑地點。G1的死角不多。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"설마, 녀석들이 그런 엉뚱한 장소에 나타날 줄은 몰랐지만.","JPN":"まさかやつらがあんな突拍子もない場所に現れるとは思わなかったけど。","ENG":"Didn't expect them to show up somewhere that random, though.","TWN":"只是我沒想到他們會出現在那種地方。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"보안을 뚫고 대균열 안으로 들어가려 했어요. 거기서 뭘 얻으려던 걸까요?","JPN":"セキュリティを突破して大亀裂の中に入ろうとしていました。そこで何をするつもりだったんでしょうか。","ENG":"They tried to break through security and enter the Grand Dimension Crevice. What were they after?","TWN":"他們突破保安、進入大峽谷，是為了拿到什麼？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"글쎄.","JPN":"さあね。","ENG":"Who knows.","TWN":"這個我也不清楚。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"방금 전까지 침식사태를 수습하는 동안 실종자 신고가 제법 들어왔어.","JPN":"さっきまで侵食事態を収拾してたんだけど、失踪者の報告が結構入ってきてた。","ENG":"While we were dealing with the Corruption disaster earlier, we got quite a few missing person reports.","TWN":"剛才處理侵蝕事件時，也收到不少失蹤通報。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"당연히 그 침입자 놈들의 짓이라 생각했는데… 착각이 아니라면 놈들의 계략은 한 두 가지가 아닌 것 같아.","JPN":"当然侵入者どもの仕業だと思ってたけど……こうなると、騒ぎ1つや2つどころじゃ済まないかもしれないわね。","ENG":"Naturally, I assumed it was the intruders' doing... But if I'm not mistaken, they're running more than one scheme at once.","TWN":"我本來以為都是那些入侵者搞的鬼……但如果我沒猜錯，他們的計畫不只一個。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"벨제부브라고 했었죠? 침입자들은 그 마왕이란 존재를 따르는 거고요.","JPN":"ベルゼブブでしたっけ？　侵入者たちはその魔王に従っているんですね。","ENG":"You said Beelzebub, right? The intruders serve that Demon Lord.","TWN":"你剛說別西卜對吧？入侵者就是追隨那個魔王吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yeah.","TWN":"嗯。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"마왕이란 건… 민하 씨에게 있어서 상대할 만한 존재인가요?","JPN":"魔王というのは……ミウさんにとって、相手ができそうな存在なんですか？","ENG":"A Demon Lord is... something you can actually face, Minha?","TWN":"魔王……對敏荷來說，是能對付的對象嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"아마 어렵지 않을까?","JPN":"難しいんじゃないかな。","ENG":"Probably not easily.","TWN":"應該不難吧？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그래도 벨제부브가 내 앞에 직접 나타난다면, 도망칠 수 있어도 싸우긴 할 거야.","JPN":"でもベルゼブブが私の前に現れたら、とりあえず戦うつもり。逃げるチャンスがあってもね。","ENG":"Still, if Beelzebub showed up in front of me, I'd fight. Even if running away were an option.","TWN":"但如果別西卜親自出現在我面前，就算逃得了，我也會選擇戰鬥。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그건, 공인 카운터로서의 사명 같은 건가요?","JPN":"公認カウンターとしての使命感ですか？","ENG":"Is that a sense of duty, as an Official Counter?","TWN":"那是作為認證制裁者的使命嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"풋, 그런 사명이 있었으면 시니어 말대로 얌전히 그라운드 원이나 지켰겠지.","JPN":"ぷっ、使命感なんてもんがあったら、シニアの言う通り大人しくグラウンド・ワンを守ってたよ。","ENG":"Pfft. If I had that kind of sense of duty, I'd have stayed put guarding Ground One like the Senior wanted.","TWN":"噗。如果真有那種使命感，我早就乖乖守在G1了。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"원래 그라운드 원의 공인 카운터는 내가 아니었어.","JPN":"もともとグラウンド・ワンの公認カウンターは私じゃなかった。","ENG":"I wasn't originally Ground One's Official Counter.","TWN":"原本G1的認證制裁者不是我。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"잠깐 공석이 된 그 자릴 어쩌다 보니 내가 떠맡았을 뿐이야.","JPN":"少しの間空席になっていたその役目を、なりゆきで任されてしまっただけ。","ENG":"The position opened up for a bit, and I just ended up taking it.","TWN":"只是那個位置一度空缺，剛好被我接下來而已。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"공인 카운터의 자리가 공석이 됐다는 건… 어떤 의미죠?","JPN":"公認カウンターが空席って……どういうことですか？","ENG":"If the Official Counter position became vacant... what does that mean?","TWN":"認證制裁者的位置空缺……那代表什麼意思？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"살해당했어.","JPN":"殺されたんだ。","ENG":"The former one was murdered.","TWN":"被殺了。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L24_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"마왕 벨제부브의 낙인이 찍힌 채로.","JPN":"魔王ベルゼブブの烙印が押されて。","ENG":"Branded with the mark of the Demon Lord Beelzebub.","TWN":"在被烙上魔王別西卜的烙印後。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…살해…","JPN":"……殺された……","ENG":"...Murdered...","TWN":"……被殺……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"2년 전, 그 배후를 파헤치던 사람들이 전부 죽었어.","JPN":"2年前、背後を探っていた人は全員死んだ。","ENG":"Two years ago, everyone who tried to dig into what was behind them died.","TWN":"2年前，追查他們底細的人全都死了。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그 중엔 <color=#ffd34c>S급 카운터</color>도 있었고.","JPN":"その中には<color=#ffd34c>S級カウンター</color>だっていた。","ENG":"That included a <color=#ffd34c>Grade S Counter</color>.","TWN":"其中還有<color=#ffd34c>S級制裁者</color>。"},"stage":{"bg":"CITY_CENTER1","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"지금 민하 씨가 하고 있는 건…누군가의 복수인가요?","JPN":"今ミウさんがやろうとしているのは……誰かの復讐ですか？","ENG":"What you're doing now... is it revenge for someone?","TWN":"現在敏荷正在做的事……是某個人的復仇嗎？"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그 사람은 나한테 인생을 가르쳐준 스승이었어. 유일한 가족이기도 했고.","JPN":"その人は私に人生を教えてくれた師匠で、唯一の家族だった。","ENG":"That person was my master. The one who taught me how to live. My only family.","TWN":"那個人，是我的人生導師，也是我唯一的家人。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"언니는 이해 못할 거야. 이미 죽은 사람 때문에, 이렇게까지 한다는 거.","JPN":"姉さんにはわからないかもね。死んだ人のためにここまでやるってのが。","ENG":"You wouldn't understand. Going this far over someone who's already dead.","TWN":"姐姐你不會懂的。因為一個已經死去的人，做到這種地步。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"아니에요. 실은 저도…","JPN":"そんなことありません。実は私も……","ENG":"No. Actually, I–","TWN":"不，其實我也……"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"으앗!","JPN":"わっ！","ENG":"Whoa!","TWN":"呀啊！"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"신호가 가까워.","JPN":"信号が近い。","ENG":"The signal's close.","TWN":"訊號就在附近。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L42_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"저 공장부지 안쪽이야. 가자.","JPN":"あっちの工場の敷地内ね、行こ！","ENG":"Inside that factory complex. Let's go.","TWN":"就在那座工廠用地裡面，走吧。"},"stage":{"bg":"CAR","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}},"sfx":"FX_CUTSCEN_DOOR_CAR"},{"id":"L46_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_A","text":{"KOREA":"살려주세요. 저한테 왜 그러시는 거예요.","JPN":"やめてください！　どうしてこんなことをするんですか！？","ENG":"Please, let me go. Why are you doing this to me?","TWN":"救命啊。為什麼要這樣對我？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"이거 풀어줘! 난 아무한테도 원한 같은 거 산 적 없다고!","JPN":"くっ、放せ！　俺が何をしたっていうんだ！","ENG":"Untie me! I've never wronged anyone!","TWN":"放開我！我又沒跟任何人結仇！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"놀랄 것 없다. 이것을 먹고 거룩한 뜻에 동참하면 될 뿐이다.","JPN":"驚くには及ばぬ。これを食し、共に聖なる意志を果たすのだ。","ENG":"There's nothing to be afraid of. Just eat this and join the holy will.","TWN":"沒什麼好驚訝的。只要吃下這個，參與神聖的旨意即可。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"이건, 올리브?","JPN":"これは……オリーブ？","ENG":"This is... an olive?","TWN":"這是橄欖？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"욱… 썩었잖아.","JPN":"うっ……腐ってる。","ENG":"Ugh... it's rotten.","TWN":"嘔……都爛了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"식음은 작은 행위이나 그것이 곧 다가올 종말 앞에 너희를 평온케 하리라.","JPN":"飲食は些細な行為。しかし、来たるべき終末を目前にしたお前たちに、平穏を授けるであろう。","ENG":"Food is a small act, but before the coming end, it will bring you peace.","TWN":"進食只是微不足道的行為。但在即將到來的末日前，它會讓你們獲得安寧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"저리 치워! 이딴 걸 어떻게 먹으란 거야!","JPN":"要らねえよ！　こんなもん食えるわけねえだろ！","ENG":"Get that away from me! How am I supposed to eat this?!","TWN":"拿走！這種東西怎麼吃得下去！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"…뜻에 따르지 아니한다면, 우리가 너를 먹어 대속하리라.","JPN":"……意志に従わぬというならば、我らがお前を食し、この身をもって贖罪しよう。","ENG":"...If you refuse to follow the will, then we shall eat you in your stead.","TWN":"……若不遵循旨意，那麼就由我們吃掉你代為贖罪。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"힉! 얼굴이… 사람이 아니잖아!","JPN":"ひっ！　顔が……人間じゃない！","ENG":"Eek! Your face... You're not human!","TWN":"呀啊！那張臉……根本不是人啊！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"먹을게요! 먹으면 되잖아!","JPN":"食べます！　食べればいいんだろう！","ENG":"I'll eat it! I'll eat it, okay?!","TWN":"我吃！我吃就是了！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"욱… 우욱… 속이 이상해.","JPN":"う、うぐっ……気持ち悪い。","ENG":"Ugh... urgh... My stomach feels strange.","TWN":"嘔……嗚……肚子好奇怪。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"뱀이 기어 다니는 것 같아.","JPN":"ヘビが体中を這い回っている感じがする……","ENG":"It feels like snakes are crawling inside me.","TWN":"好像有蛇在裡面爬。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"이로서, 충분한 제물과 의식이 준비되었다.","JPN":"これにて生贄も儀式も備わった。","ENG":"Thus, sufficient offerings and the ritual are prepared.","TWN":"這樣就準備好足夠的祭品與儀式了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"머잖아 그분의 검은 숨결이 저들의 내장을 찢고 나와 이 작은 섬을 뒤덮으리라.","JPN":"ほどなく、あのお方の黒き息吹が彼の者らの内蔵を裂きて顕れ、この小さき島を覆い尽くさん。","ENG":"Before long, her black breath will tear through their entrails and blanket this small island.","TWN":"不久之後，那位的黑色吐息將撕裂他們的內臟，覆蓋整座小島。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"잠깐… 뭐라고? 방금 뭐라고 한 거야?","JPN":"待て……何だって？　今なんて言った？","ENG":"W-wait... what did you just say?","TWN":"等等……什麼？你剛剛說什麼？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"너희는 의식이 성사되면, 방해자들의 시신을 딛고 넘어 작은 왕을 찾아라.","JPN":"お前たちは儀式成就ののち、妨げし者どもの屍を越え小さき王を探せ。","ENG":"Once the ritual is complete, trample over the bodies of those who interfere and seek out the little queen.","TWN":"儀式完成後，踩著妨礙者的屍體去尋找小王吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"감정의 파편이 암군의 손에 닿지 못하게 하라.","JPN":"感情の破片が暗君の手に触れることを阻止せよ。","ENG":"Do not let the fragment of emotion reach the Ignorant Monarch.","TWN":"別讓情感的碎片落入暗軍手中。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"당신들, 우리한테 뭘 먹인 거야! 무슨 짓을 하려고…! 오, 오지 마!","JPN":"俺たちに何を食わせたんだ！　何のつもりでっ……！　く、来るな！","ENG":"What did you feed us?! What are you trying to do...?! D-don't come any closer!","TWN":"你們到底給我們吃了什麼！想做什麼……！不、不要過來！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L22_1","type":"dialog","speaker":"CULTIST_NPC_NULL_ENTER","text":{"KOREA":"너희의 공포는 그분의 숨결을 더 멀리 퍼트리는 매개일 뿐.","JPN":"お前たちの恐怖はあのお方の息吹をより広める媒介に過ぎない。","ENG":"Your fear is merely a medium that spreads her breath even farther.","TWN":"你們的恐懼，只會成為讓那位的吐息擴散得更遠的媒介。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"CULTIST_NPC_NULL_ENTER","text":{"KOREA":"지금부터 의식을 거행하겠나이다.","JPN":"これより儀式を執り行う。","ENG":"We shall now commence the ritual.","TWN":"現在，開始舉行儀式。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"CULTIST_NPC_NULL_ENTER","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CULTIST_NPC_NULL_ENTER","text":{"KOREA":"너너… 는는?","JPN":"オオマエ……ハハ？","ENG":"Y-you... a-are?!","TWN":"你、你是……？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_ENTER","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DEMON_ROOT_NPC_QM","text":{"KOREA":"사람의 목숨을 사람을 죽이는 재앙과 맞바꾸려 하다니…","JPN":"人の命と引き換えに人を殺す災害を起こそうとは……","ENG":"To trade a human life for a calamity that kills humans...","TWN":"竟然想用人類的性命，交換會殺死更多人的災厄……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L29_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"여러분이 따르는 신께서는 아무래도 고장 난 저울을 쓰고 계신 모양이네요.","JPN":"皆さんが仕えている神様は、どうやら壊れた天秤をお使いのようですね。","ENG":"It seems the god you follow is using a broken scale.","TWN":"看來你們信奉的神，使用的是壞掉的天秤呢。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_SKILL_START"},{"id":"L31_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"…옛 낙원의 악마여.","JPN":"……かつての楽園の悪魔よ。","ENG":"...Devil of the fallen Promise Land.","TWN":"……舊樂園的魔鬼啊。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"영혼을 탐하는 기생충 주제에. 우릴 방해한 이유가 희생양을 지키려는 소명은 아닐 테지.","JPN":"魂を貪る寄生虫の分際で我らに刃を向けるか。よもや生贄を守らんがための義ではあるまい。","ENG":"You parasite that feeds on souls. You did not interfere out of some noble duty to protect sacrifices, did you?","TWN":"不過是個吞噬靈魂的寄生蟲。你妨礙我們，總不會是因為想守護祭品吧？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"그럴 리가요, 소라껍데기 씨. 그런 가벼운 명분으로 정해진 운명에 간섭할 순 없죠.","JPN":"勿論違いますよ、ミスター巻貝。そんな軽はずみな名分で、定められた運命に干渉するのもどうかと思いますし。","ENG":"Of course not, Mr. Conch. I wouldn't meddle with a fixed fate over such a flimsy cause.","TWN":"怎麼可能呢，海螺殼。我才不會因為那麼輕薄的名分，就干涉既定的命運。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"그저… 타기리온의 약점을 훔쳐 게임의 우위를 취하겠다는 파리의 계략이 제 마음에 들지 않았을 뿐이랍니다.","JPN":"ただ……タギリオンの弱点を我がものとし、ゲームで優位に立とうというハエの計略が、少し気に入らなかっただけです。","ENG":"I merely... found the flies' scheme to steal Thagirion's weakness and gain the upper hand rather distasteful.","TWN":"我只是……不太欣賞礙眼的東西偷走塔基里翁弱點、藉此取得遊戲優勢的策略而已。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"그분이 뜻하심을 알고 있음에도 훼방을 놓았단 건, 암군을 돕겠단 뜻인가?","JPN":"あのお方の思し召しと知りながら邪魔をする、と。……すなわち、暗君に与するということか？","ENG":"Even knowing her will, you still interfered. Does that mean you intend to aid the Ignorant Monarch?","TWN":"你明知那位的意志卻仍出手妨礙，這代表你打算幫助暗軍嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"그렇다면 너는 다시 그녀의 수족으로 돌아간 건가?","JPN":"再び、彼女の手足と成ったと？","ENG":"Then have you returned to serving her once more?","TWN":"那麼，你又要回到她的麾下了？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"전 지금도, 앞으로도, 누군가에게 속해질 생각이 없습니다.","JPN":"私は今も、これからも、誰かに属するつもりはありません。","ENG":"I belong to no one, now or ever.","TWN":"我無論現在或未來，都不打算隸屬於任何人。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"하지만 기껏 기다려온 별의 화려한 최후가 그런 단조로운 태양빛에 가려져선 곤란해요.","JPN":"ですが待ち侘びてきた星の華麗な最後が、単調な太陽光に隠れては困ります。","ENG":"Still, it would be troublesome if the spectacular finale of the star I've waited so long for were obscured by such monotonous sunlight.","TWN":"只是好不容易等到的星星華麗落幕，若被單調的太陽光掩蓋，可就傷腦筋了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"허나 이미 늦었다.","JPN":"だがもはや手遅れだ。","ENG":"But it's already too late.","TWN":"但已經太遲了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"지금 우릴 모두 죽여도, 여섯 대균열의 거울이 파괴되는 건 막을 수 없으리라.","JPN":"今ここで我らを屠ろうとも、6つの大亀裂の鏡が砕かれる定めは覆せない。","ENG":"Even if you kill us all now, you won't be able to stop the destruction of the six Grand Dimension Crevice mirrors.","TWN":"就算現在殺了我們所有人，也無法阻止六座大峽谷之鏡被破壞。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"아, 당신들이 대균열에 은밀히 심어둔 검은 죽음의 살점들을 말하는 걸까요?","JPN":"ああ、あなたたちが密かに大亀裂に仕込んだ、黒き死の肉片のことですか？","ENG":"Ah, you mean the pieces of Black Death you secretly planted in the Grand Dimension Crevices?","TWN":"啊，你是說你們偷偷植入大峽谷中的那些黑死肉塊嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_MONSTER_MINISTRA_SKILL_START"},{"id":"L43_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"전 거기까진 관여하지 않을 겁니다. 타기리온의 사도가 안배한 거울이 제때 작동해버린다면 그건 오히려 타기리온에게 너무 유리하죠.","JPN":"そこまで干渉するつもりはありません。タギリオンの使徒が手配した鏡がタイミングよく作動してしまうと、タギリオンにとって都合が良すぎますから。","ENG":"I won't involve myself that far. If the mirror arranged by Thagirion's Apostle activates on time, it would benefit Thagirion far too much.","TWN":"我就不介入那一步了。若塔基里翁的使徒安排的鏡子準時啟動，反倒對塔基里翁太有利了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"게임은 공정하게 치르는 편이 재밌으니까요. 그렇지 않습니까?","JPN":"ゲームはフェアでないと面白味に欠ける……そう思いませんか？","ENG":"Games are more fun when they're played fairly. Don't you agree?","TWN":"遊戲嘛，還是公平一點比較有趣，不是嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"네가 바라보는 건… 클리포트 게임이 아니구나.","JPN":"お前が見据えているのは……クリフォトゲームではあるまいな。","ENG":"What you seek... is not the Qliphoth Game.","TWN":"你所注視的……已經不是逆卡巴拉遊戲了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"화두가 그런 것에만 머무르면 이야기가 너무 늘어집니다. 이제 끝을 내야죠.","JPN":"そういう話題ばかりだと話が長くなります。そろそろ終わりにしましょう。","ENG":"If we dwell on that, this will drag on too long. It's time to end this.","TWN":"如果話題只停留在那裡，故事就會拖得太長。是時候結束了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"CULTIST_NPC_NULL_SPEAK","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_NPC_NULL_SPEAK","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…찾았다! 사람들이 여기 있… 응?","JPN":"……見つけた！　みんながここに……うん？","ENG":"...Found them! The people are here– Huh?","TWN":"……找到了！人就在這裡……咦？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L4_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"오.","JPN":"お。","ENG":"Oh.","TWN":"哦。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"뭐야? 호박대가리?","JPN":"何だ？　カボチャ頭？","ENG":"Huh? Pumpkin head?","TWN":"什麼啊？南瓜頭？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"너도 여기 추종자들이랑 한 패냐?","JPN":"あんたもこいつらとぐるってこと？","ENG":"Are you with those followers too?","TWN":"你跟這些追隨者是一夥的嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"소동만 정리하고 조용히 떠날 생각이었는데…","JPN":"騒ぎを鎮めて静かに去るつもりでしたが……","ENG":"I was planning to clean up the mess and leave quietly...","TWN":"我原本打算收拾完騷動就安靜離開……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"예정보다 일찍 도착했군요.","JPN":"予定より早く着いてしまいましたね。","ENG":"You arrived earlier than expected.","TWN":"沒想到你比我預期還早到。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"이 녀석들을 전부 해치운 게 너야?","JPN":"あんたが、こいつらを全部やっつけたの？","ENG":"You're the one who took all of them out?","TWN":"是你把這些傢伙全都解決的？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"공로를 치하 해주시면 기쁘게 받겠지만, 지금은 좀 바빠서요.","JPN":"功績を称えていただけるのは嬉しいのですが、今は少し急いでいますので。","ENG":"I'd gladly accept praise, but I'm a bit busy right now.","TWN":"如果你願意給我記上一功，我也不介意。不過我現在有點忙。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"멈춰.","JPN":"動くな。","ENG":"Stop.","TWN":"住手。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"}}}},{"id":"L15_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"얼굴 좀 확인하게 그 호박탈부터 벗어봐.","JPN":"そのカボチャ、脱いでくれる？　顔を確かめておきたくてね。","ENG":"Take that pumpkin mask off. Let me see your face.","TWN":"摘下那南瓜面具，讓我看看臉。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"…그건 어렵습니다.","JPN":"……それはできません。","ENG":"...That will be difficult.","TWN":"……那恐怕辦不到。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"이건 탈이 아니라 저의…","JPN":"これは被り物ではなく、私の……","ENG":"This isn't a mask. It's my–","TWN":"這不是面具，而是我的……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"총탄? 어디서 날아온 거지?","JPN":"銃弾？　どっから飛んできた？","ENG":"A gunshot? Where did that come from?","TWN":"子彈？從哪來的？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L25_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"커헉…!","JPN":"かはっ……！","ENG":"Guh...!","TWN":"咳……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…죽었어?","JPN":"……死んだ？","ENG":"...Is he dead?","TWN":"……死了？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"제가 쐈어요.","JPN":"私が撃ちました。","ENG":"I shot him.","TWN":"是我開的槍。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"언니?","JPN":"姉さん？","ENG":"Nicole?","TWN":"姐姐？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"갑자기 왜 돌발행동이야?! 이 사람은 아직 우리 적인지도 모른다고!","JPN":"なんでいきなり撃つのよ！？　まだ敵かどうかすらわかってないのに！","ENG":"Why did you act so suddenly?! We don't even know if he's our enemy yet!","TWN":"你怎麼突然擅自行動？！都還沒確認這個人是不是敵人啊！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"얕은 수작으로 절 기만할 생각은 마시죠.","JPN":"見え透いた小細工で私を騙せると思わないでください。","ENG":"Don't think you can deceive me with such shallow tricks.","TWN":"別想用拙劣的把戲欺騙我。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"악마.","JPN":"悪魔。","ENG":"Devil.","TWN":"魔鬼。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"…악마?","JPN":"……悪魔？","ENG":"...Devil?","TWN":"……魔鬼？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"살아있어? 그걸 맞고도 멀쩡하다고?","JPN":"生きてる？　あれに撃たれて無事だなんて……？","ENG":"He's alive? He took that and still looks fine?","TWN":"居然沒死？你中那一槍居然沒事？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"놀랐습니다. 그 거리에서 저를 알아보고, 정확히 심장을 노릴 줄이야.","JPN":"驚きました。あの距離から私を認識し、正確に心臓を狙うとは。","ENG":"Impressive. To recognize me from that distance and aim straight for the heart.","TWN":"真令人驚訝。居然能在那種距離認出我，還準確瞄準心臟。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"멀리서 봐도 알겠더군요.","JPN":"遠くからでも一目でわかりました。","ENG":"I could tell even from afar.","TWN":"就算隔那麼遠，我一眼就認出來了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L43_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"적지 않은 시간이 흘렀는데도… 그 머리통이 너무 또렷하게 각인되어 있었거든.","JPN":"あの時からかなりの時が経ったけど……その頭の形は鮮明に脳裏に焼き付いて離れなかったから。","ENG":"Even after all this time... that head was burned too clearly into my memory.","TWN":"明明過了這麼久……那顆腦袋卻清晰地烙印在我腦中。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L44_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"저는 당신에게 딱히 악감정은 없습니다만.","JPN":"私はあなたに悪い感情は持っていませんが。","ENG":"I bear no particular ill will toward you.","TWN":"我跟你沒有什麼私人恩怨。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"저 역시 맹세했죠. 사적인 증오는 품지 않기로.","JPN":"私も誓いました。個人的な憎悪は抱かないと。","ENG":"I made a vow as well. To harbor no personal hatred.","TWN":"我也曾發過誓，不再懷恨在心。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그 대신, 악마를 멸한다는 성무를 짊어지기로…!","JPN":"その代わり、悪魔を滅するという聖務を負うと……！","ENG":"Instead, I chose to bear the sacred mission of exterminating devils...!","TWN":"取而代之的，是背負殲滅魔鬼的聖務……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L49_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"이건- 플람마 아스페길룸… 성황청의 그 몬시뇰이 당신에게 전수해준 모양이군요.","JPN":"これは、フランマ・アスペルギルム……どうやら聖皇庁のモンシニョールから授けられたようですね。","ENG":"This is... Flamma Aspergillum. It seems that the Monsignor of Holy Curia taught it to you.","TWN":"這是—火焰淨化……看來是聖皇廳的那位蒙席傳授給你的吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"하지만 핵심을 노리지 못하고 흩어지는 불꽃으론 저를 멸할 수 없을 겁니다.","JPN":"ですが、核心を狙えず散ってしまう炎では、私を滅することは叶わないでしょう。","ENG":"But scattered flames that miss the vital point won't be enough to destroy me.","TWN":"不過無法命中要害、四散的火焰，是無法消滅我的。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"닥쳐요.","JPN":"黙りなさい。","ENG":"Shut up.","TWN":"閉嘴。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"히, 히익! 시체가…!","JPN":"ひ、ひいっ！　死体が……！","ENG":"E-eeek! The corpses...!","TWN":"呀、呀啊！屍體……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CITIZEN_OMEN_G1_B","text":{"KOREA":"시체가 살아 움직인다!","JPN":"死体が動いてる！","ENG":"The corpses are moving!","TWN":"屍體動起來了！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"파리 자식들… 아직 죽은 게 아니었어?","JPN":"ハエども……まだ死んでなかったの？","ENG":"Those fly bastards... they're not dead yet?","TWN":"那些礙眼的東西……還沒死嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_SCREAM"},{"id":"L10_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"그런데 생기가 전혀 안 느껴져.","JPN":"でも、まったく生気を感じない。","ENG":"And there's no sign of life at all.","TWN":"可是感覺不到一點生氣。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"게다가 저 호박머리는…?","JPN":"それに、あのカボチャ頭は……？","ENG":"And that pumpkin head...?","TWN":"而且那個南瓜頭是……？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…피해요!","JPN":"……避けて！","ENG":"...Get back!","TWN":"……快閃開！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"읏?!","JPN":"っ！？","ENG":"Ugh?!","TWN":"呃？！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"머릴 맞혀도, 계속 움직인다고…?","JPN":"頭を撃っても動いてる……？","ENG":"Even shooting them in the head, they keep moving...?","TWN":"打中頭部，還會繼續動……？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L33_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"이 시체들, 조종당하고 있는 거 같아.","JPN":"この死体たち、操られてるみたい。","ENG":"These corpses are being controlled.","TWN":"這些屍體，好像被操縱了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"저를 원망하는 마음은 이해합니다, 니콜 프라이머.","JPN":"私を恨む気持ちはわかります、ニコル・プライマー。","ENG":"I understand your resentment, Nicole Primer.","TWN":"我能理解你怨恨我，妮可．布萊伊莫。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L36_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"하지만 당신에겐 과거의 청산보다 더 중요한 일이 있지 않나요?","JPN":"ですがあなたには過去を清算するよりも大事なことがあるのではないですか？","ENG":"But isn't there something more important to you than settling the past?","TWN":"但比起清算過去，你現在有更重要的事吧？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"모르가나 모드렛.","JPN":"モルガナ・モードレッド。","ENG":"Morgana Modred.","TWN":"莫甘娜．莫德雷。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그 아일 건들 생각 마.","JPN":"あの子には手出しさせない。","ENG":"Don't touch that child.","TWN":"你別打那孩子的主意。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"그전에 내가 널 먼저 퇴치할 테니까.","JPN":"その前に、私があなたを滅してやる。","ENG":"Before that, I'll exterminate you first.","TWN":"在那之前，我會先解決你。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"그 아이를 노리는 건 저뿐만이 아닙니다. 당신도 이젠 알고 있을 텐데요?","JPN":"知ってのとおり、あの子を狙っているのは私だけではありません。","ENG":"I'm not the only one after the child. You know that now, don't you?","TWN":"你應該也已經知道，想對那孩子出手的可不只我一個了吧？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"벨제부브를 말하는 거라면…","JPN":"ベルゼブブのことなら……","ENG":"If you mean Beelzebub...","TWN":"如果你指的是別西卜……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"후후, 그자는 두려워할 뿐입니다.","JPN":"ふふ、あの者はただ恐れているだけです。","ENG":"Haha. That one is simply afraid.","TWN":"呵呵，那傢伙只是在害怕罷了。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"자신보다 더 위협적인 존재가 그 아이를 노리고 있음을 알기에, 먼저 선수를 치려 했을 뿐이죠.","JPN":"自分より脅威的な存在があの子を狙っていることを知っているがゆえに、先手を打とうとしたのです。","ENG":"Knowing that something even more dangerous than herself is targeting the child, she merely tried to strike first.","TWN":"因為他知道，有比自己更具威脅的存在正在覬覦那孩子，所以才想捷足先登。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"벨제부브가… 무언가를 두려워한다고?","JPN":"ベルゼブブが……何かを恐れているだって？","ENG":"Beelzebub... is afraid of something?","TWN":"別西卜……在怕什麼？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"아주 오래 전…","JPN":"遠い昔……","ENG":"A very long time ago...","TWN":"很久以前……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"타기리온이라 불리는 마왕은 자신의 심장이나 다름없던 파편을 한 악마에게 빼앗겼습니다.","JPN":"タギリオンと呼ばれる魔王は、自分の心臓も同然だった破片をとある悪魔に奪われました。","ENG":"The Devil Lord known as Thagirion lost a Fragment that was no different from her own heart, stolen by a devil.","TWN":"被稱為塔基里翁的魔王，曾被某個魔鬼奪走了如同自己心臟一樣重要的碎片。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"그 악마는 자신이 가장 아끼는 존재를 죽음으로부터 구하기 위해 마왕의 파편을 사용했고, 그 파편은 지금도 한 소녀의 몸 속에 깃들어 있죠.","JPN":"その悪魔は己の最も大事な存在を死より救うために魔王の破片を使い、その破片は今も一人の少女の身体に宿っています。","ENG":"That devil used the Fragment to save the one they cherished most from death, and that fragment still dwells within a young girl even now.","TWN":"那個魔鬼為了拯救自己最珍愛之人免於死亡，使用了魔王的碎片。而那個碎片，至今仍寄宿在某個少女體內。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"마왕의… 파편?","JPN":"魔王の……破片？","ENG":"A Fragment... of the Demon Lord?","TWN":"魔王的……碎片？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"날 속일 생각 마, 악마! 모모에게 그런 게 있을 리가…!","JPN":"そんな嘘に騙されるもんか、悪魔め！　モモにそんなものがあるはずが……！","ENG":"Don't try to deceive me, devil! There's no way Momo has something like that...!","TWN":"別想騙我，魔鬼！那種東西不可能在莫莫身上……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"그 소녀의 머리에 뿔이 자라고, 자신을 마왕이라 믿는 것이 그저 우연일까요?","JPN":"あの少女の頭に角が生え、自身を魔王と信じているのはただの偶然だと思いますか？","ENG":"Is it truly just a coincidence that horns grew from the girl's head, and that she believes herself to be a Demon Lord?","TWN":"那個少女頭上長出角、深信自己是魔王，真的只是巧合嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MOMO_BAR_NULL_NULL","text":{"KOREA":"이 몸은 위대한 마왕 모르가나 모드렛이다!","JPN":"吾輩は偉大なる魔王、モルガナ・モードレッドである！","ENG":"I'm the great Demon Lord, Morgana Mordred!","TWN":"本王，正是偉大的魔王莫甘娜．莫德雷！"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"MOMO_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"임금님에 대해서라면 걱정하지 않아도 돼.","JPN":"王様のことなら心配しなくても大丈夫よ。","ENG":"You don't have to worry about her.","TWN":"不用擔心那位國王。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"세상엔 행운을 부르는 힘을 받은 사람이 있듯이, 불운을 끌어들이는 힘을 떠맡은 사람도 있거든.","JPN":"世の中には幸運を呼ぶ力を授かった人がいるように、不運を招く力を引き受けてしまった人もいるのよ。","ENG":"Just as some people attract good luck, some people attract bad luck.","TWN":"世上既有被賦予招來幸運之力的人，也有被迫承擔吸引不幸之力的人。"},"stage":{"bg":"GREMORY_BAR","bgm":"CUTSCENE_TALK_02","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"불운으로 위장한 죽음이 매일 그 소녀의 목숨을 노려오는 것 역시, 그 파편의 주인인 마왕이 살아 끼치는 영향 때문이라고 한다면-","JPN":"不運を装った死が毎日彼女の命を狙ってくるのも、その破片の主である魔王が生きていることでもたらす影響だとしたら……","ENG":"If even the deaths disguised as mere bad luck that come for the girl's life day after day are the lingering influence of the Demon Lord who owns that Fragment...","TWN":"若每天偽裝成不幸死亡、不斷威脅那名少女性命的，正是那碎片主人仍活著所造成的影響—"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"당신이 지금껏 품어온 모든 의문의 아귀가 맞아떨어지지 않습니까?","JPN":"あなたがこれまで抱いていた疑問のすべてに、説明がつくのではないですか？","ENG":"Doesn't that make every doubt you've carried until now fall perfectly into place?","TWN":"那麼，你至今抱持的所有疑問，不就全都串起來了嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"머잖아- 당신의 운명이 당신을 가장 원대한 적에게로 인도할 겁니다.","JPN":"まもなく、あなたの運命があなたを最も偉大な敵へと導くでしょう。","ENG":"Before long, your fate will lead you to your greatest enemy.","TWN":"不久之後—你的命運，將會引領你前往面對最宏大的敵人。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"그러니 지금 품은 증오는 당신의 진정한 적을 위해 아껴두세요.","JPN":"ですから今胸に抱いている憎悪は、あなたの真の敵のために取っておいてください。","ENG":"So save the hatred you hold now for your true foe.","TWN":"所以，把現在這份憎恨，留給你真正的敵人吧。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"멈춰요! 어딜 가려고!","JPN":"くっ、待ちなさい！","ENG":"Stop! Where do you think you're going?!","TWN":"站住！你要去哪裡！！"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"DEMON_OMEN_NPC_NULL","text":{"KOREA":"그때까지, 안녕히-","JPN":"その時まで、ごきげんよう。","ENG":"Until then... farewell–","TWN":"在那之前，再會了—"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DEMON_OMEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINHA_G1_NUL.L_NULL","text":{"KOREA":"쳇, 저것들 사이에 숨은 건가?","JPN":"ちっ、やつらの中に紛れたか？","ENG":"Tch, did he hide among them?","TWN":"嘖，是躲進那些傢伙裡面了嗎？"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_TALK_02","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L28_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"찾아내죠.","JPN":"探し出しましょう。","ENG":"We'll find him.","TWN":"那就要找出來。"},"stage":{"bg":"DOCK_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MINHA_G1_NUL.L_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_03"},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_PR","text":{"KOREA":"전부 부숴서라도…!","JPN":"全部ぶち壊してでも……！","ENG":"Even if we have to smash everything to pieces...!","TWN":"就算要破壞一切……！"},"stage":{"bg":"DOCK_NIGHT","bgm":"BATTLE_BOSS_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_PR","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};